   104	
   105	    // Add text before the match
   106	    if (match.index > lastIndex) {
   107	      result.push({
   108	        type: 'text',
   109	        text: text.slice(lastIndex, match.index),
   110	      });
   111	    }
   112	
   113	    // If issue exists, add as link; otherwise, add as plain text
   114	    if (issue) {
   115	      result.push({
   116	        type: 'text',
   117	        text: match[0],
   118	        marks: [
   119	          {
   120	            type: 'link',
   121	            attrs: {
   122	              href: `/issues/${issue.id}`,
   123	              target: '_self',
   124	            },
   125	          },
   126	        ],
   127	      });
   128	    } else {
   129	      result.push({
   130	        type: 'text',
   131	        text: match[0],
   132	      });
   133	    }
   134	
   135	    lastIndex = match.index + match[0].length;
   136	  }
   137	
   138	  // Add remaining text
   139	  if (lastIndex < text.length) {
   140	    result.push({
   141	      type: 'text',
   142	      text: text.slice(lastIndex),
   143	    });
   144	  }
   145	
   146	  return result;
   147	}
   148	
   149	/**
   150	 * Recursively transform nodes
   151	 */
   152	function transformNodes(
   153	  nodes: TipTapNode[],
   154	  issueMap: Map<number, IssueInfo>
   155	): TipTapNode[] {
   156	  const result: TipTapNode[] = [];
   157	
   158	  for (const node of nodes) {
   159	    if (node.type === 'text' && node.text) {
   160	      // Don't transform text that already has marks (like existing links)
   161	      if (node.marks && node.marks.length > 0) {
