{"success":true,"content":"     1	/**
     2	 * Transform issue reference patterns in TipTap JSON content to clickable links.
     3	 *
     4	 * Detects patterns:
     5	 * - #123
     6	 * - issue #123
     7	 * - ISS-123
     8	 *
     9	 * Replaces with TipTap link marks pointing to /issues/:id
    10	 */
    11	
    12	import { pool } from '../db/client.js';
    13	import { isTipTapDoc, type TipTapDoc, type TipTapNode } from '@ship/shared';
    14	
    15	interface IssueInfo {
    16	  id: string;
    17	  ticket_number: number;
    18	}
    19	
    20	// Pattern to match issue references: #123, issue #123, ISS-123
    21	// Captures the full match and the number
    22	const ISSUE_PATTERN = /(?:#(\d+)|issue\s+#?(\d+)|ISS-(\d+))/gi;
    23	
    24	/**
    25	 * Look up issues by ticket numbers in a workspace
    26	 */
    27	async function lookupIssuesByTicketNumbers(
    28	  workspaceId: string,
    29	  ticketNumbers: number[]
    30	): Promise<Map<number, IssueInfo>> {
    31	  if (ticketNumbers.length === 0) return new Map();
    32	
    33	  const result = await pool.query(
    34	    `SELECT id, ticket_number FROM documents
    35	     WHERE workspace_id = $1
    36	       AND document_type = 'issue'
    37	       AND ticket_number = ANY($2::int[])`,
    38	    [workspaceId, ticketNumbers]
    39	  );
    40	
    41	  const issueMap = new Map<number, IssueInfo>();
    42	  for (const row of result.rows) {
    43	    issueMap.set(row.ticket_number, {
    44	      id: row.id,
    45	      ticket_number: row.ticket_number,
    46	    });
    47	  }
    48	
    49	  return issueMap;
    50	}
    51	
    52	/**
    53	 * Extract ticket numbers from text
    54	 */
    55	function extractTicketNumbers(text: string): number[] {
    56	  const numbers: number[] = [];
    57	  let match;
    58	  const pattern = new RegExp(ISSUE_PATTERN.source, 'gi');
    59	
    60	  while ((match = pattern.exec(text)) !== null) {
    61	    // Match groups: #123 → [1], issue #123 → [2], ISS-123 → [3]
    62	    const num = parseInt(match[1] ?? match[2] ?? match[3] ?? '', 10);
    63	    if (!isNaN(num) && !numbers.includes(num)) {
    64	      numbers.push(num);
    65	    }
    66	  }
    67	
    68	  return numbers;
    69	}
    70	
    71	/**
    72	 * Recursively extract all ticket numbers from TipTap content
    73	 */
    74	function extractAllTicketNumbers(nodes: TipTapNode[]): number[] {
    75	  const numbers: number[] = [];
    76	
    77	  for (const node of nodes) {
    78	    if (node.type === 'text' && node.text) {
    79	      numbers.push(...extractTicketNumbers(node.text));
    80	    }
    81	    if (node.content) {
    82	      numbers.push(...extractAllTicketNumbers(node.content));
    83	    }
    84	  }
    85	
    86	  return [...new Set(numbers)];
    87	}
    88	
    89	/**
    90	 * Transform text node by replacing issue patterns with link marks
    91	 */
    92	function transformTextNode(
    93	  text: string,
    94	  issueMap: Map<number, IssueInfo>
    95	): TipTapNode[] {
    96	  const result: TipTapNode[] = [];
    97	  let lastIndex = 0;
    98	  const pattern = new RegExp(ISSUE_PATTERN.source, 'gi');
    99	  let match;
   100	
   101	  while ((match = pattern.exec(text)) !== null) {
   102	    const num = parseInt(match[1] ?? match[2] ?? match[3] ?? '', 10);
   103	    const issue = issueMap.get(num);
   104	
   105	    // Add text before the match
   106	    if (match.index > lastIndex) {
   107	      result.push({
   108	        type: 'text',
   109	        text: text.slice(lastIndex, match.index),
   110	      });
   111	    }
   112	
   113	    // If issue exists, add as link; otherwise, add as plain text
   114	    if (issue) {
   115	      result.push({
   116	        type: 'text',
   117	        text: match[0],
   118	        marks: [
   119	          {
   120	            type: 'link',
   121	            attrs: {
   122	              href: `/issues/${issue.id}`,
   123	              target: '_self',
   124	            },
   125	          },
   126	        ],
   127	      });
   128	    } else {
   129	      result.push({
   130	        type: 'text',
   131	        text: match[0],
   132	      });
   133	    }
   134	
   135	    lastIndex = match.index + match[0].length;
   136	  }
   137	
   138	  // Add remaining text
   139	  if (lastIndex < text.length) {
   140	    result.push({
   141	      type: 'text',
   142	      text: text.slice(lastIndex),
   143	    });
   144	  }
   145	
   146	  return result;
   147	}
   148	
   149	/**
   150	 * Recursively transform nodes
   151	 */
   152	function transformNodes(
   153	  nodes: TipTapNode[],
   154	  issueMap: Map<number, IssueInfo>
   155	): TipTapNode[] {
   156	  const result: TipTapNode[] = [];
   157	
   158	  for (const node of nodes) {
   159	    if (node.type === 'text' && node.text) {
   160	      // Don't transform text that already has marks (like existing links)
   161	      if (node.marks && node.marks.length > 0) {
   162	        result.push(node);
   163	      } else {
   164	        // Transform this text node
   165	        const transformed = transformTextNode(node.text, issueMap);
   166	        result.push(...transformed);
   167	      }
   168	    } else if (node.content) {
   169	      // Recursively transform child content
   170	      result.push({
   171	        ...node,
   172	        content: transformNodes(node.content, issueMap),
   173	      });
   174	    } else {
   175	      result.push(node);
   176	    }
   177	  }
   178	
   179	  return result;
   180	}
   181	
   182	/**
   183	 * Transform issue reference patterns in TipTap JSON content to clickable links.
   184	 *
   185	 * @param content - TipTap JSON document
   186	 * @param workspaceId - Workspace ID for issue lookup
   187	 * @param preloadedIssueMap - Optional pre-fetched issue map to avoid N+1 queries in batch scenarios
   188	 * @returns Transformed TipTap JSON with issue links
   189	 */
   190	export async function transformIssueLinks(
   191	  content: unknown,
   192	  workspaceId: string,
   193	  preloadedIssueMap?: Map<number, IssueInfo>
   194	): Promise<unknown> {
   195	  if (!isTipTapDoc(content)) return content;
   196	
   197	  const doc: TipTapDoc = content;
   198	
   199	  // Extract all ticket numbers from content
   200	  const ticketNumbers = extractAllTicketNumbers(doc.content);
   201	  if (ticketNumbers.length === 0) return content;
   202	
   203	  // Use preloaded map if provided, otherwise look up
   204	  let issueMap: Map<number, IssueInfo>;
   205	  if (preloadedIssueMap) {
   206	    // Filter the preloaded map to only include ticket numbers found in this content
   207	    issueMap = new Map();
   208	    for (const num of ticketNumbers) {
   209	      const issue = preloadedIssueMap.get(num);
   210	      if (issue) {
   211	        issueMap.set(num, issue);
   212	      }
   213	    }
   214	  } else {
   215	    issueMap = await lookupIssuesByTicketNumbers(workspaceId, ticketNumbers);
   216	  }
   217	
   218	  if (issueMap.size === 0) return content;
   219	
   220	  // Transform the content
   221	  return {
   222	    ...doc,
   223	    content: transformNodes(doc.content, issueMap),
   224	  };
   225	}
   226	
   227	/**
   228	 * Extract all ticket numbers from multiple TipTap JSON documents.
   229	 * Useful for batch pre-loading issue data to avoid N+1 queries.
   230	 *
   231	 * @param contents - Array of TipTap JSON documents
   232	 * @returns Deduplicated list of ticket numbers
   233	 */
   234	export function extractTicketNumbersFromContents(contents: unknown[]): number[] {
   235	  const allNumbers: number[] = [];
   236	
   237	  for (const content of contents) {
   238	    if (!isTipTapDoc(content)) continue;
   239	
   240	    const doc: TipTapDoc = content;
   241	
   242	    allNumbers.push(...extractAllTicketNumbers(doc.content));
   243	  }
   244	
   245	  return [...new Set(allNumbers)];
   246	}
   247	
   248	/**
   249	 * Batch lookup issues by ticket numbers.
   250	 * Use this to pre-fetch issue data before calling transformIssueLinks multiple times.
   251	 *
   252	 * @param workspaceId - Workspace ID for issue lookup
   253	 * @param ticketNumbers - Array of ticket numbers to look up
   254	 * @returns Map of ticket number to issue info
   255	 */
   256	export async function batchLookupIssues(
   257	  workspaceId: string,
   258	  ticketNumbers: number[]
   259	): Promise<Map<number, IssueInfo>> {
   260	  return lookupIssuesByTicketNumbers(workspaceId, ticketNumbers);
   261	}
